const body = $input.first().json.body ?? $input.first().json;
const { seq_step_id, milestone_status, appointment_status, notify_patient = false } = body;

const VALID_MILESTONE = ['waiting', 'done', 'alert', 'pending'];
const VALID_APPT_STATUS = ['scheduled', 'confirmed', 'completed', 'cancelled'];

if (!seq_step_id) throw new Error('seq_step_id is required');
if (!VALID_MILESTONE.includes(milestone_status)) throw new Error(`Invalid milestone_status: ${milestone_status}`);
if (appointment_status && !VALID_APPT_STATUS.includes(appointment_status)) throw new Error(`Invalid appointment_status: ${appointment_status}`);

return [{ json: {
  seq_step_id:        parseInt(seq_step_id, 10),
  milestone_status,
  appointment_status: appointment_status || null,
  notify_patient:     !!notify_patient,
} }];

