-- Update treatment_seq_steps milestone_status
UPDATE treatment_seq_steps
SET milestone_status = '{{ $json.milestone_status }}', updated_at = NOW()
WHERE id = {{ $json.seq_step_id }};

-- Optionally sync appointments.status
DO $$
DECLARE
  v_appt_id UUID;
  v_appt_status TEXT := '{{ $json.appointment_status }}';
BEGIN
  SELECT appointment_id INTO v_appt_id FROM treatment_seq_steps WHERE id = {{ $json.seq_step_id }};
  IF v_appt_id IS NOT NULL AND v_appt_status <> '' AND v_appt_status <> 'null' THEN
    UPDATE appointments SET status = v_appt_status, updated_at = NOW() WHERE id = v_appt_id;
  END IF;
END $$;

-- Auto-complete sequence if all steps are done
UPDATE treatment_sequences ts
SET status = 'completed'
FROM treatment_seq_steps s
WHERE ts.id = s.sequence_id
  AND s.id = {{ $json.seq_step_id }}
  AND NOT EXISTS (
    SELECT 1 FROM treatment_seq_steps x
    WHERE x.sequence_id = ts.id
      AND x.milestone_status != 'done'
  )

