const rows = $input.all().filter(r => r.json.id);
if (rows.length === 0) throw new Error('Step not found after update');
const r = rows[0].json;
return [{ json: {
  success: true,
  step: {
    id: r.id,
    step_number: r.step_number,
    step_name: r.step_name,
    scheduled_date: r.scheduled_date || null,
    appointment_id: r.appointment_id || null,
    is_lab_pending: !!r.is_lab_pending,
    status: r.milestone_status === 'done'    ? 'completed'
          : r.milestone_status === 'waiting' ? 'scheduled'
          : r.milestone_status === 'alert'   ? 'missed'
          : 'pending',
    notes: r.notes || null,
    completed_at: r.completed_at || null,
  },
  sequence_completed: r.sequence_status === 'completed',
} }];
